#!/usr/bin/env npx tsx
/**
 * All-DeepSeek overnight multi-agent orchestrator (generic, role-based skeleton).
 *
 * Generated by the `deepseek-overnight` skill. An ARBITRARY set of agents runs
 * on DeepSeek via the @anthropic-ai/claude-code SDK, organized by ROLE:
 *
 *   - planner   : runs BEFORE the dev wave. Reads the previous stage's outcome
 *                 + BLOCKED.md and produces/adjusts this stage's guidance. Also
 *                 triages blocked items (replan an alternative, or mark for the
 *                 morning) — the overnight stand-in for human escalation.
 *   - worker    : builds the code. A "researcher" is just a worker with no gates.
 *   - reviewer  : advisory critic. Add several for multi-critic review (e.g. one
 *                 security, one API-design); their change requests are merged.
 *
 * Each stage runs:  PLAN → DEV (waves) → GATE → REVIEW (N critics) → FIX → loop.
 * Reliability comes from the deterministic GATE MACHINE (not the reviewers),
 * frozen spec tests, a DeepSeek-only guard, conditional commits, readable logs.
 *
 * FILL every section marked `CONFIG — FILL PER PROJECT`; leave the machinery.
 *
 * Launch:
 *   export ANTHROPIC_BASE_URL="https://api.deepseek.com/anthropic"
 *   export ANTHROPIC_AUTH_TOKEN="$DEEPSEEK_API_KEY"
 *   npx tsx orchestrate.ts --stage 0
 *   npx tsx orchestrate.ts --continuous
 *   npx tsx orchestrate.ts --stage 3 --skip a2,researcher
 */

